import React, { useContext, useState } from "react";
import { Context } from "../../Context";
import { AdminAuth, createProfileForUser, getProfileByAuthId } from "../../service/Profile.service";
import { Auth } from "aws-amplify";
import { navigate } from "gatsby";


const AdminSignInForm = () => {
  
  const { SignIn } = useContext(Context);
  const [formData, setFormData] = useState({ username: "", password: ""});
  const [ isShowSignIn, setIsShowSignIn ] = SignIn;

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };
  

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const user = await Auth.signIn(formData.username, formData.password);
      //** Check is there profile */        
      const profile = await getProfileByAuthId(user.attributes.sub); 
      if(!profile?.data?.listProfiles?.items.length){
        let input = {
          auth_id: user.attributes.sub,
          email: user.attributes.email,
        }
        await createProfileForUser(input);
      }
      // ## Check if user is admin or not
      const isAdmin =  await AdminAuth();
      if(isAdmin){
        navigate('/admin')
      }else{
        alert("You are not authorized to access this route, previlages are only for admin")
        navigate('/');
      }

      setIsShowSignIn(false)
    } catch (err) {
      console.log('error signing in', err);
      setIsShowSignIn(true)
    }
   
  }
  return (
      <div className="flex min-h-screen items-center justify-center bg-gray-100 p-4">
        <div className="w-full max-w-md bg-white p-10 rounded-3xl shadow-lg">
          <h2 className="text-3xl font-bold text-center text-gray-800 mb-8">Sign In</h2>
          <form onSubmit={handleSubmit}>
            <div className="mb-6">
              <label className="block text-gray-700 text-sm font-medium mb-2">Email</label>
              <input
                type="email"
                name="username"
                value={formData.username}
                onChange={handleChange}
                className="w-full px-4 py-3 border rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500"
                required
              />
            </div>
            <div className="mb-6">
              <label className="block text-gray-700 text-sm font-medium mb-2">Password</label>
              <input
                type="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                className="w-full px-4 py-3 border rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500"
                required
              />
            </div>
            <button
              type="submit"
              className="w-full bg-blue-500 hover:bg-blue-600 text-white font-semibold py-3 rounded-xl transition duration-300 shadow-md"
            >
              Sign In
            </button>
            <div className="text-center mt-4 text-blue-700 underline cursor-pointer hover:text-blue-900 active:text-blue-500" onClick={()=> navigate("/")}> Go back home </div>
          </form>
        
        </div>
      </div>
    
  );
}

export default AdminSignInForm